const income = Number($json.income);
const saved = Number($json.saved);
const invested = Number($json.invested);
const expenses = Number($json.expenses);

// Handle zero income
if (income === 0) {
  return [{
    json: {
      income,
      saved,
      invested,
      expenses,
      savingScore: 0,
      investmentScore: 0,
      expenseScore: 0,
      finalScore: 0,
      status: "Income cannot be zero"
    }
  }];
}

// Ratios
let savingRatio = saved / income;
let investmentRatio = invested / income;
let expenseRatio = expenses / income;

//  Saving Score (higher is better)
let savingScore = 0;
if (savingRatio >= 0.3) savingScore = 100;
else if (savingRatio >= 0.2) savingScore = 70;
else if (savingRatio > 0) savingScore = 40;
else savingScore = 0;

//  Investment Score (higher is better)
let investmentScore = 0;
if (investmentRatio >= 0.2) investmentScore = 100;
else if (investmentRatio > 0) investmentScore = 60;
else investmentScore = 0;

//  Expense Score (lower expense = better)
let expenseScore = 0;
if (expenseRatio <= 0.5) expenseScore = 100;
else if (expenseRatio <= 0.7) expenseScore = 60;
else expenseScore = 30;

//  Final Score (average of all 3)
let finalScore = (savingScore + investmentScore + expenseScore) / 3;

//  Status
let status = "";
if (finalScore >= 80) status = "Excellent";
else if (finalScore >= 50) status = "Good";
else status = "Needs Improvement";

//  Return ALL fields (important for Google Sheets)
return [{
  json: {
    income,
    saved,
    invested,
    expenses,
    savingScore,
    investmentScore,
    expenseScore,
    finalScore: finalScore.toFixed(2),
    status
  }
}];

