let alert = "";

if (expenses > income * 0.7) {
    alert = "Warning : Your expenses are very high!";
} else if (expenses > income * 0.5) {
    alert = "Caution: Keep an eye on your expenses.";
} else {
    alert = "Good! Expenses are under control.";
}

return [{ json: { ...$json, expenseAlert: alert } }];

